import sys

class Solution:
    def findLIS(self, nums: list[int]) -> int:
        n = len(nums)
        if n == 1:
            return 1
        dp = [[1, 1] for _ in range(n)]
        max_len = 1
        for i in range(1, n):
            for j in range(i):
                if nums[i] > nums[j]:
                    if dp[i][0] < dp[j][0] + 1:
                        dp[i][0] = dp[j][0] + 1
                        dp[i][1] = dp[j][1]
                    elif dp[i][0] == dp[j][0] + 1:
                        dp[i][1] += dp[j][1]
            if dp[i][0] > max_len:
                max_len = dp[i][0]
        count = 0
        for i in range(n):
            if dp[i][0] == max_len:
                count += dp[i][1]
        return count

